// SES Lockdown stub for Phase 0.
//
// In the real build, this file is replaced by the full SES bundle
// from @endo/ses (generated by `yarn build` in packages/ses).
// For Phase 0, we simulate the lockdown surface to verify the
// V8 host can load and evaluate JS correctly.
//
// The real SES lockdown:
//   1. Freezes all JS intrinsics (Object, Array, Function, etc.)
//   2. Provides harden() as a global
//   3. Provides Compartment as a global
//   4. Removes unsafe globals (eval in its raw form, etc.)
//
// This stub provides just enough to test the boot sequence.

(function sesLockdownStub() {
  'use strict';

  // Simulate harden() — in real SES this deep-freezes an object
  // graph and returns it.
  function harden(obj) {
    if (typeof obj === 'object' && obj !== null) {
      Object.freeze(obj);
    }
    return obj;
  }

  // Simulate Compartment — in real SES this creates a sandboxed
  // evaluation environment with controlled globals.
  function Compartment(endowments, modules, options) {
    this.globalThis = Object.create(null);
    if (endowments) {
      Object.assign(this.globalThis, endowments);
    }
  }
  Compartment.prototype.evaluate = function(source) {
    // In Phase 0, just use the real eval.  The real SES
    // Compartment uses a safe evaluator with frozen intrinsics.
    return (0, eval)(source);
  };

  // Install globals.
  globalThis.harden = harden;
  globalThis.Compartment = Compartment;

  // Simulate lockdown() — the real version freezes everything.
  globalThis.lockdown = function lockdown(options) {
    print('ses: lockdown() applied (Phase 0 stub)');
    // Freeze our own surface.
    Object.freeze(harden);
    Object.freeze(Compartment);
    Object.freeze(Compartment.prototype);
  };

  print('ses: SES lockdown module loaded (Phase 0 stub)');
})();
